  const winnerCopy=make('div','winner-copy'); winnerCopy.appendChild(make('span','pill ok','✓ Winner'));
  winnerCopy.appendChild(make('h2','',String(winner.name)));
  if(winner.badge) winnerCopy.appendChild(make('div','winner-badge',String(winner.badge)));
  winnerRow.appendChild(winnerCopy); hero.appendChild(winnerRow); frame.appendChild(hero);
  const body=make('div','body');
  body.appendChild(make('p','rationale',data.rationale?String(data.rationale):'No rationale supplied.'));
  if(reasons.length){
    body.appendChild(make('div','section-title','Why it wins'));
    const list=make('div','reasons');
    reasons.forEach((reason) => { const item=make('div','reason'); item.appendChild(make('span','check','✓')); item.appendChild(make('span','',String(reason))); list.appendChild(item); });
    body.appendChild(list);
  }
  if(bestFor.length){
    body.appendChild(make('div','section-title','Best for'));
    const personas=make('div','personas');
    bestFor.forEach((item) => {
      const tag=make('div','persona'); tag.appendChild(make('span','persona-icon','●'));
      const copy=make('span',''); copy.appendChild(make('strong','',item&&item.persona!=null?String(item.persona):'Unspecified'));
      if(item&&item.reason) copy.appendChild(make('small','',String(item.reason))); tag.appendChild(copy); personas.appendChild(tag);
    });
    body.appendChild(personas);
  }
  if(data.runnerUp||data.caveat){
    const foot=make('div','foot');
    if(data.runnerUp){
      const card=make('div','note-card'); card.appendChild(make('div','note-label','Runner-up'));
      card.appendChild(make('div','note-value',String(data.runnerUp.name)+(data.runnerUp.reason?' — '+String(data.runnerUp.reason):''))); foot.appendChild(card);
    }
    if(data.caveat){
      const card=make('div','note-card caution'); card.appendChild(make('span','pill partial','Partial trade-off'));
      card.appendChild(make('div','note-value',String(data.caveat))); foot.appendChild(card);
    }
    body.appendChild(foot);
  }
  frame.appendChild(body);
}
root.appendChild(frame);
parent.appendChild(host);
